import React from 'react'
import useData from '../useData'
import useSplitPaymentStore from '../useSplitPaymentStore'

export function PlanCard({ plan, onClick }) {
    if (plan) {
        const { planTitle, planDuration, planTag, id } = plan
        return (
            <div className='border-4 border-indigo-500 rounded-lg bg-grey' onClick={() => onClick(plan)}>
                <div className='p-2 text-4xl text-blue-600 dark:text-sky-400'>{planTitle}</div>
                <div className='p-2 text-4xl text-blue-600 dark:text-sky-400'>{planTag}</div>
                <div className='p-2 text-4xl text-blue-600 dark:text-sky-400'>{planDuration + ' ' + 'months'}</div>
            </div>
        )
    }
}
function Plans() {
    const { data, loading, error } = useData()
    const setActivePlan = useSplitPaymentStore((s) => s.setActivePlan)

    function handleClick(plan) {
        setActivePlan(plan)
    }

    if (data) {
        return (
            <div className='grid grid-cols-4 gap-4'>
                {data.map((plan) => {
                    return (<PlanCard key={plan.id} plan={plan} onClick={handleClick} />)
                })}
            </div>
        )
    }
}

export default Plans
